{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>EXG팀 주간업무 보고서 생성기</title>
<link rel="preconnect" href="https://fonts.googleapis.com">
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
<style>
:root {
  --red: #A50034;
  --red-mid: #c4003d;
  --red-light: #f9e6ec;
  --dark: #1a1a1a;
  --g900: #222;
  --g700: #4b4b4d;
  --g500: #787a7d;
  --g300: #c8c8c8;
  --g100: #f4f4f4;
  --white: #fff;
  --yellow: #FBBF24;
  --text-dark: #1F2937;
  --bg-light: #F3F4F6;
  --font: 'Noto Sans KR', system-ui, sans-serif;
  --radius: 16px;
  --radius-sm: 10px;
  --shadow: 0 4px 24px rgba(0,0,0,.08);
  --shadow-lg: 0 12px 48px rgba(0,0,0,.12);
}
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font); background: #F9FAFB; color: var(--text-dark); min-height: 100vh; }

/* ── TOP BAR ── */
.top-bar {
  background: rgba(26,26,26,.95);
  backdrop-filter: blur(12px);
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 40px; height: 52px;
  position: fixed; top: 0; left: 0; right: 0; z-index: 200;
  border-bottom: 1px solid rgba(255,255,255,.06);
}
.top-bar-left { display: flex; align-items: center; gap: 12px; }
.top-bar-logo { color: var(--red); font-size: 20px; font-weight: 900; letter-spacing: -0.5px; }
.top-bar-sep { width: 1px; height: 18px; background: rgba(255,255,255,.15); }
.top-bar-title { color: rgba(255,255,255,.75); font-size: 13px; font-weight: 400; }
.top-bar-right { display: flex; align-items: center; gap: 8px; }
.api-status { font-size: 12px; padding: 4px 12px; border-radius: 20px; font-weight: 500; }
.api-status.ok { background: rgba(16,185,129,.15); color: #10b981; }
.api-status.warn { background: rgba(251,191,36,.15); color: var(--yellow); }

/* ── HERO ── */
.hero {
  margin-top: 52px;
  background: linear-gradient(165deg, #0d0d0d 0%, #1a1a2e 40%, #16213e 70%, #0f3460 100%);
  padding: 56px 40px 48px; position: relative; overflow: hidden;
}
.hero::before {
  content: ''; position: absolute; top: -50%; left: -10%; width: 120%; height: 200%;
  background: radial-gradient(ellipse at 30% 20%, rgba(165,0,52,.15) 0%, transparent 60%);
  pointer-events: none;
}
.hero-inner { max-width: 960px; margin: 0 auto; position: relative; z-index: 1; }
.hero-badge {
  display: inline-flex; align-items: center; gap: 6px;
  background: rgba(165,0,52,.18); border: 1px solid rgba(165,0,52,.3);
  color: #ff6b8a; font-size: 12px; font-weight: 700; letter-spacing: .15em;
  padding: 5px 14px; border-radius: 20px; margin-bottom: 18px; text-transform: uppercase;
}
.hero h1 { color: var(--white); font-size: clamp(26px, 4vw, 38px); font-weight: 900; letter-spacing: -1px; line-height: 1.2; margin-bottom: 10px; }
.hero h1 span { color: var(--red); }
.hero p { color: rgba(255,255,255,.6); font-size: 15px; line-height: 1.7; }
.hero-meta { display: flex; gap: 24px; margin-top: 24px; flex-wrap: wrap; }
.hero-meta-item { display: flex; align-items: center; gap: 8px; color: rgba(255,255,255,.5); font-size: 13px; }
.hero-meta-item i { color: var(--red); font-size: 14px; }

/* ── MAIN LAYOUT ── */
.main { max-width: 960px; margin: 0 auto; padding: 40px 24px 80px; }

/* ── SECTION TITLES ── */
.section-label {
  font-size: 12px; font-weight: 700; letter-spacing: .15em; text-transform: uppercase;
  color: var(--red); margin-bottom: 8px;
}
.section-title { font-size: 22px; font-weight: 700; color: var(--text-dark); margin-bottom: 20px; }

/* ── CONFIG CARD ── */
.config-card {
  background: var(--white); border-radius: var(--radius); padding: 28px 32px;
  box-shadow: var(--shadow); border: 1.5px solid var(--red-light); margin-bottom: 24px;
}
.config-grid { display: grid; grid-template-columns: 100px 80px 1fr 160px; gap: 14px; align-items: end; }
.field-group label { display: block; font-size: 12px; font-weight: 500; color: var(--g500); margin-bottom: 6px; }
.field-group input, .field-group select {
  width: 100%; font-family: var(--font); font-size: 14px; font-weight: 500;
  padding: 10px 14px; border: 1.5px solid var(--g300); border-radius: var(--radius-sm);
  color: var(--text-dark); background: var(--white); outline: none; transition: border-color .2s;
}
.field-group input:focus, .field-group select:focus { border-color: var(--red); }
.api-key-row { display: flex; gap: 10px; margin-top: 16px; padding-top: 16px; border-top: 1px solid var(--g100); align-items: end; }
.api-key-row .field-group { flex: 1; }
.api-key-row .field-group input { font-family: monospace; font-size: 13px; letter-spacing: .05em; }
.btn-sm {
  padding: 10px 16px; font-family: var(--font); font-size: 13px; font-weight: 500;
  border-radius: var(--radius-sm); cursor: pointer; border: 1.5px solid var(--g300);
  background: var(--white); color: var(--g700); transition: all .2s; white-space: nowrap;
}
.btn-sm:hover { border-color: var(--red); color: var(--red); }

/* ── TASK PRESETS ── */
.preset-row { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 20px; }
.preset-chip {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 6px 14px; border-radius: 20px; font-size: 13px; font-weight: 500; cursor: pointer;
  border: 1.5px solid var(--g300); background: var(--white); color: var(--g700);
  transition: all .2s; font-family: var(--font);
}
.preset-chip:hover { border-color: var(--red); color: var(--red); background: var(--red-light); }
.preset-chip i { font-size: 11px; }

/* ── TASK CARD ── */
.task-card {
  background: var(--white); border-radius: var(--radius); padding: 24px 28px;
  box-shadow: var(--shadow); border: 1.5px solid var(--g100); margin-bottom: 14px;
  transition: border-color .2s;
}
.task-card:hover { border-color: var(--g300); }
.task-card-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; }
.task-card-title { display: flex; align-items: center; gap: 10px; }
.task-number {
  width: 28px; height: 28px; background: var(--red); border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: var(--white); font-size: 13px; font-weight: 700; flex-shrink: 0;
}
.task-name-display { font-size: 15px; font-weight: 700; color: var(--text-dark); }
.task-tag-badge {
  padding: 3px 10px; border-radius: 20px; font-size: 11px; font-weight: 700; letter-spacing: .08em;
}
.tag-ax { background: rgba(165,0,52,.1); color: var(--red); }
.tag-edu { background: rgba(59,130,246,.1); color: #3b82f6; }
.tag-org { background: rgba(16,185,129,.1); color: #059669; }
.tag-ops { background: rgba(107,114,128,.1); color: #6b7280; }
.task-remove {
  background: none; border: none; cursor: pointer; color: var(--g300); font-size: 18px;
  padding: 2px 6px; border-radius: 6px; transition: color .2s;
}
.task-remove:hover { color: #ef4444; }
.task-fields-row { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-bottom: 12px; }
.task-fields-row .field-group input, .task-fields-row .field-group select {
  font-size: 13px; padding: 8px 12px;
}
textarea {
  width: 100%; font-family: var(--font); font-size: 13px; line-height: 1.7;
  padding: 10px 14px; border: 1.5px solid var(--g300); border-radius: var(--radius-sm);
  color: var(--text-dark); background: var(--white); resize: vertical; outline: none;
  transition: border-color .2s;
}
textarea:focus { border-color: var(--red); }
.field-group label span.req { color: var(--red); margin-left: 2px; }
.ctx-area { font-size: 12px; color: var(--g500); background: var(--g100); min-height: 56px; }

/* ── ADD TASK BUTTON ── */
.add-task-btn {
  width: 100%; padding: 16px; border: 2px dashed var(--g300); background: none;
  border-radius: var(--radius); font-family: var(--font); font-size: 14px; font-weight: 500;
  color: var(--g500); cursor: pointer; transition: all .2s; margin-bottom: 28px;
}
.add-task-btn:hover { border-color: var(--red); color: var(--red); background: var(--red-light); }

/* ── GENERATE BUTTON ── */
.generate-row { display: flex; gap: 12px; align-items: center; margin-bottom: 32px; }
.btn-generate {
  padding: 14px 36px; background: var(--red); color: var(--white);
  border: none; border-radius: var(--radius-sm); font-family: var(--font);
  font-size: 15px; font-weight: 700; cursor: pointer; transition: all .25s;
  display: flex; align-items: center; gap: 8px;
}
.btn-generate:hover { background: var(--red-mid); transform: translateY(-1px); box-shadow: 0 8px 24px rgba(165,0,52,.3); }
.btn-generate:disabled { background: var(--g300); cursor: not-allowed; transform: none; box-shadow: none; }
.btn-clear {
  padding: 14px 20px; background: var(--white); color: var(--g700);
  border: 1.5px solid var(--g300); border-radius: var(--radius-sm); font-family: var(--font);
  font-size: 14px; font-weight: 500; cursor: pointer; transition: all .2s;
}
.btn-clear:hover { border-color: var(--g700); }
.spinner { display: inline-block; width: 16px; height: 16px; border: 2px solid rgba(255,255,255,.4); border-top-color: var(--white); border-radius: 50%; animation: spin .7s linear infinite; }
@keyframes spin { to { transform: rotate(360deg); } }

/* ── OUTPUT SECTION ── */
.output-section { margin-top: 8px; }
.output-header {
  display: flex; justify-content: space-between; align-items: center;
  margin-bottom: 20px; padding-bottom: 16px; border-bottom: 2px solid var(--red-light);
}
.output-header h2 { font-size: 20px; font-weight: 700; color: var(--text-dark); }
.output-header h2 span { color: var(--red); }
.btn-copy-all {
  padding: 8px 18px; background: var(--text-dark); color: var(--white);
  border: none; border-radius: var(--radius-sm); font-family: var(--font);
  font-size: 13px; font-weight: 500; cursor: pointer; display: flex; align-items: center; gap: 6px;
  transition: all .2s;
}
.btn-copy-all:hover { background: var(--g900); }

.output-card {
  background: var(--white); border-radius: var(--radius); padding: 24px 28px;
  box-shadow: var(--shadow); border: 1.5px solid var(--g100); margin-bottom: 14px;
}
.output-card-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; }
.output-card-title { display: flex; align-items: center; gap: 10px; }
.output-cols { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
.output-col-label {
  display: flex; justify-content: space-between; align-items: center;
  font-size: 11px; font-weight: 700; letter-spacing: .12em; text-transform: uppercase;
  color: var(--g500); margin-bottom: 8px;
}
.output-content {
  background: var(--g100); border-radius: var(--radius-sm); padding: 14px 16px;
  font-size: 13px; line-height: 1.8; white-space: pre-wrap; color: var(--text-dark);
  min-height: 80px;
}
.btn-copy {
  padding: 3px 10px; background: var(--white); border: 1px solid var(--g300);
  border-radius: 6px; font-family: var(--font); font-size: 11px; font-weight: 500;
  color: var(--g700); cursor: pointer; transition: all .2s;
}
.btn-copy:hover { border-color: var(--red); color: var(--red); }
.btn-copy.copied { border-color: #10b981; color: #10b981; }
.btn-save-ctx {
  margin-top: 12px; padding: 7px 14px; background: none; border: 1px solid var(--g300);
  border-radius: var(--radius-sm); font-family: var(--font); font-size: 12px; font-weight: 500;
  color: var(--g500); cursor: pointer; display: flex; align-items: center; gap: 6px;
  transition: all .2s;
}
.btn-save-ctx:hover { border-color: var(--red); color: var(--red); }
.btn-save-ctx.saved { border-color: #10b981; color: #10b981; }

/* ── ERROR / INFO ── */
.alert {
  padding: 12px 16px; border-radius: var(--radius-sm); font-size: 13px; margin-top: 12px;
}
.alert-err { background: #fef2f2; border-left: 3px solid #ef4444; color: #dc2626; }
.alert-info { background: #eff6ff; border-left: 3px solid #3b82f6; color: #1d4ed8; }

/* ── LOADING STATE ── */
.loading-card {
  background: var(--white); border-radius: var(--radius); padding: 32px 28px;
  box-shadow: var(--shadow); text-align: center; border: 1.5px solid var(--red-light);
  margin-bottom: 14px;
}
.loading-card .spinner-lg {
  display: inline-block; width: 28px; height: 28px;
  border: 3px solid var(--red-light); border-top-color: var(--red);
  border-radius: 50%; animation: spin .8s linear infinite; margin-bottom: 12px;
}
.loading-card p { font-size: 14px; color: var(--g500); }
.loading-card .task-hint { font-size: 15px; font-weight: 700; color: var(--text-dark); margin-bottom: 4px; }

/* ── FOOTER ── */
.footer {
  background: var(--dark); padding: 28px 40px;
  display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 12px;
}
.footer-left { color: rgba(255,255,255,.4); font-size: 12px; }
.footer-left span { color: var(--red); font-weight: 700; }
.footer-right { color: rgba(255,255,255,.3); font-size: 12px; }

/* ── RESPONSIVE ── */
@media(max-width: 768px) {
  .top-bar { padding: 0 20px; }
  .hero { padding: 40px 20px 36px; }
  .main { padding: 28px 16px 60px; }
  .config-grid { grid-template-columns: 1fr 1fr; }
  .config-grid .field-group:last-child { grid-column: span 2; }
  .task-fields-row { grid-template-columns: 1fr; }
  .output-cols { grid-template-columns: 1fr; }
  .generate-row { flex-direction: column; align-items: stretch; }
}
</style>
</head>
<body>

<!-- TOP BAR -->
