        <label>Anthropic API Key <span style="color:var(--g500);font-weight:400;">(Claude API — 로컬에서만 사용, 저장되지 않음)</span></label>
        <input type="password" id="api-key" placeholder="sk-ant-..." oninput="checkApiKey()">
