</div>

<!-- FOOTER -->
<div class="footer">
  <div class="footer-left">
    <span>LG PRI EXG팀</span> · 주간업무 보고서 자동생성 시스템 v1.0
  </div>
  <div class="footer-right">Powered by Claude API · 입력 데이터는 로컬에서만 처리됩니다</div>
</div>

<script>
// ── 상수 & 데이터 ──
const PRESETS = [
  { name: "AX 역량인증제\n(모두의 AX제도변경)", tag: "AX", icon: "fa-certificate" },
  { name: "AX기반의 Pulse Check\n체계구축",         tag: "AX", icon: "fa-heart-pulse" },
  { name: "HR실 AX 역량 강화",                       tag: "AX", icon: "fa-brain" },
  { name: "Physical AI 역량강화",                    tag: "AX", icon: "fa-robot" },
  { name: "PRI 기술 전문가 커미티",                  tag: "교육", icon: "fa-users" },
  { name: "AX 아카데미",                             tag: "교육", icon: "fa-graduation-cap" },
  { name: "어학운영",                                tag: "교육", icon: "fa-language" },
];

const HISTORY = {
  "AX 역량인증제\n(모두의 AX제도변경)": {
    week: "6일~10일",
    content: `● [AX] "모두의 AX" 인증제 운영\n  - 생산기술원 관점의 최적 적용 운영안 검토 및 리뷰 준비(w/AX 커미티)\n  - 신규 LV1 인증 절차 안내 및 운영\n  - 각 레벨별 학습 내용 매칭 작업 진행`
  },
  "AX기반의 Pulse Check\n체계구축": {
    week: "6일~10일",
    content: `● [AX] 조직 건강도 시스템 4월 MVP 범위 확정 및 모듈별 개발 착수\n  - 4월 기준 MVP 구현 범위 결정\n  - Pulse 화면 구성 / 구성원 Attraction / 진단 응답 모듈 개발 착수`
  },
  "HR실 AX 역량 강화": {
    week: "6일~10일",
    content: `● [AX] HR실 AX역량 강화교육 준비\n  - LG화학 사내강사 초빙 협의 및 교육운영 일정(4/16, 목) 확정\n  - 강의장 확보 / 구성원 참여율 제고를 위한 사전 안내 준비`
  },
  "Physical AI 역량강화": {
    week: "9일~14일",
    content: `● [AX] Physical AI Skill Inventory 구축 준비\n  - 목적: Physical AI for Smart Factory 추진을 위한 스킬/역량의 체계적 가시화\n  - WBS 검토 및 파일럿 대상 조직 선정 진행 중`
  },
  "PRI 기술 전문가 커미티": {
    week: "3일~6일",
    content: `● PRI 기술 전문가 커미티 개편 및 Kick off 준비\n  - 목적: 생산기술원 기술별 전문가(레벨4 이상) Pool 업데이트 및 통합 역량 체계 구축\n  - Kick off 일정 확정 및 커미티 멤버 안내 완료`
  },
  "AX 아카데미": {
    week: "9일~13일",
    content: `● [AX] '26년 AX Academy 교육 운영\n  - 목적: AI Native로 일하는 방식의 근본적인 혁신을 위한 역량 확보\n  - 26년 신규과정(AX문제해결 Lab 등) 운영 및 콘텐츠 소싱 진행 중`
  },
};

const TAG_MAP = {
  AX: { label: "AX", cls: "tag-ax" },
  교육: { label: "교육", cls: "tag-edu" },
  조직문화: { label: "조직문화", cls: "tag-org" },
  운영: { label: "운영", cls: "tag-ops" },
  기타: { label: "기타", cls: "tag-ops" },
};

let tasks = [];
let taskId = 0;
let results = [];

// ── API KEY ──
function checkApiKey() {
  const key = document.getElementById("api-key").value.trim();
  const badge = document.getElementById("api-status-badge");
  const alert = document.getElementById("api-alert");
  if (key.startsWith("sk-ant-") && key.length > 20) {
    badge.className = "api-status ok";
    badge.innerHTML = '<i class="fa fa-circle" style="font-size:8px;"></i> API 연결됨';
    alert.innerHTML = "";
  } else if (key.length > 0) {
    badge.className = "api-status warn";
    badge.innerHTML = '<i class="fa fa-circle" style="font-size:8px;"></i> 키 확인 필요';
    alert.innerHTML = `<div class="alert alert-err">API 키는 "sk-ant-"로 시작해야 합니다. <a href="https://console.anthropic.com/keys" target="_blank" style="color:var(--red);">키 발급 바로가기 →</a></div>`;
  } else {
    badge.className = "api-status warn";
    badge.innerHTML = '<i class="fa fa-circle" style="font-size:8px;"></i> API 키 필요';
    alert.innerHTML = "";
  }
}

function toggleApiKeyVisibility() {
  const inp = document.getElementById("api-key");
  const icon = document.getElementById("api-eye-icon");
  if (inp.type === "password") {
    inp.type = "text";
    icon.className = "fa fa-eye-slash";
  } else {
    inp.type = "password";
    icon.className = "fa fa-eye";
  }
}

// ── PRESETS RENDER ──
function renderPresets() {
  const row = document.getElementById("preset-row");
  row.innerHTML = PRESETS.map(p => `
    <button class="preset-chip" onclick="addTaskFromPreset('${escJ(p.name)}','${p.tag}')">
      <i class="fa ${p.icon}"></i>${p.name.replace(/\n/g, ' ')}
    </button>`).join('');
}

// ── TASKS ──
function addTask(name = "", tag = "기타") {
  const id = ++taskId;
  const hist = HISTORY[name] || null;
  tasks.push({ id, name, tag, keyword: "", context: hist ? hist.content : "" });
  renderTasks();
  setTimeout(() => {
    const el = document.getElementById(`kw-${id}`);
    if (el) el.focus();
  }, 100);
}

function addTaskFromPreset(name, tag) {
  const realName = name.replace(/\\n/g, "\n");
  if (tasks.some(t => t.name === realName)) {
    const existing = tasks.find(t => t.name === realName);
    document.getElementById(`kw-${existing.id}`)?.focus();
    return;
  }
  addTask(realName, tag);
}

function removeTask(id) {
  tasks = tasks.filter(t => t.id !== id);
  renderTasks();
}

function updateTask(id, field, value) {
  const t = tasks.find(t => t.id === id);
  if (t) t[field] = value;
}

function renderTasks() {
  const c = document.getElementById("tasks-container");
  if (tasks.length === 0) {
    c.innerHTML = `<div style="text-align:center;padding:32px;color:var(--g300);font-size:14px;">
      <i class="fa fa-plus-circle" style="font-size:28px;display:block;margin-bottom:10px;"></i>
      위의 빠른 추가 버튼 또는 직접 추가 버튼으로 업무를 추가하세요
    </div>`;
    return;
  }
  c.innerHTML = tasks.map((t, i) => {
    const tagInfo = TAG_MAP[t.tag] || TAG_MAP["기타"];
    return `
    <div class="task-card" id="task-${t.id}">
      <div class="task-card-header">
        <div class="task-card-title">
          <div class="task-number">${i + 1}</div>
          <div class="task-name-display">${t.name ? escH(t.name).replace(/\n/g, ' ') : '<span style="color:var(--g300);">업무명 입력</span>'}</div>
          <span class="task-tag-badge ${tagInfo.cls}">${tagInfo.label}</span>
        </div>
        <button class="task-remove" onclick="removeTask(${t.id})" title="삭제"><i class="fa fa-xmark"></i></button>
      </div>
      <div class="task-fields-row">
        <div class="field-group">
          <label>업무명</label>
          <input type="text" value="${escH(t.name)}" placeholder="예) AX 역량인증제"
            oninput="updateTask(${t.id},'name',this.value);rerenderTaskTitle(${t.id},this.value)">
        </div>
        <div class="field-group">
          <label>분류</label>
          <select onchange="updateTask(${t.id},'tag',this.value);rerenderBadge(${t.id},this.value)">
            ${Object.keys(TAG_MAP).map(k => `<option value="${k}" ${t.tag===k?'selected':''}>${k}</option>`).join('')}
          </select>
        </div>
      </div>
      <div class="field-group" style="margin-bottom:10px;">
        <label>이번 주 핵심 내용 / 키워드 <span class="req">*</span>
          <span style="color:var(--g500);font-weight:400;"> — 메모 수준으로 짧게 써도 됩니다</span>
        </label>
        <textarea id="kw-${t.id}" rows="3"
          placeholder="예) Tester Agent 1차 완성, LV1 응시자 12명 결과 처리, 다음 주 LV2 기준 확정 예정"
          oninput="updateTask(${t.id},'keyword',this.value)">${escH(t.keyword)}</textarea>
      </div>
      <div class="field-group">
        <label>이전 주차 맥락 <span style="color:var(--g500);font-weight:400;">(자동 연속성 유지용 — 생성 후 자동 업데이트됨)</span></label>
        <textarea class="ctx-area" id="ctx-${t.id}" rows="2"
          oninput="updateTask(${t.id},'context',this.value)">${escH(t.context)}</textarea>
      </div>
    </div>`;
  }).join('');
}

function rerenderTaskTitle(id, value) {
  const el = document.querySelector(`#task-${id} .task-name-display`);
  if (el) el.innerHTML = value ? escH(value).replace(/\n/g, ' ') : '<span style="color:var(--g300);">업무명 입력</span>';
}
function rerenderBadge(id, tag) {
  const el = document.querySelector(`#task-${id} .task-tag-badge`);
  const info = TAG_MAP[tag] || TAG_MAP["기타"];
  if (el) { el.className = `task-tag-badge ${info.cls}`; el.textContent = info.label; }
}

// ── GENERATE ──
async function generateAll() {
  const apiKey = document.getElementById("api-key").value.trim();
  const year = document.getElementById("meta-year").value.trim();
  const month = document.getElementById("meta-month").value.trim();
  const week = document.getElementById("meta-week").value.trim();
  const person = document.getElementById("meta-person").value.trim();

  if (!apiKey || !apiKey.startsWith("sk-ant-")) {
    showOutputAlert("API 키를 먼저 입력해주세요. (sk-ant-...)", "err"); return;
  }
  if (!week) { showOutputAlert("주차를 입력해주세요.", "err"); return; }
  const activeTasks = tasks.filter(t => t.keyword.trim());
  if (activeTasks.length === 0) {
    showOutputAlert("핵심 내용/키워드를 최소 1개 업무에 입력해주세요.", "err"); return;
  }

  const btn = document.getElementById("btn-generate");
  btn.disabled = true;
  btn.innerHTML = '<span class="spinner"></span> 작성 중...';

  const outputArea = document.getElementById("output-area");
  outputArea.innerHTML = activeTasks.map(t => `
    <div class="loading-card" id="loading-${t.id}">
      <div class="spinner-lg"></div>
      <div class="task-hint">${escH(t.name).replace(/\n/g,' ')}</div>
      <p>AI가 보고서를 작성 중입니다...</p>
    </div>`).join('');

  results = [];
  for (const t of activeTasks) {
    try {
      const res = await callClaude(apiKey, t, year, month, week, person);
      results.push({ task: t, ...res });
    } catch(e) {
      results.push({ task: t, 실적: `[오류] ${e.message}`, 상세: "" });
    }
    const loadEl = document.getElementById(`loading-${t.id}`);
    if (loadEl) loadEl.remove();
  }

  renderOutput(year, month, week);
  btn.disabled = false;
  btn.innerHTML = '<i class="fa fa-wand-magic-sparkles"></i> 보고서 재생성';
}

async function callClaude(apiKey, task, year, month, week, person) {
  const system = `당신은 LG 생산기술원 EXG팀 HR 담당자의 주간업무 보고서를 작성하는 어시스턴트입니다.

작성 규칙:
1. 추진 업무 실적: 목적/내용/일정 구조의 bullet 형식
   형식: "● [태그] 제목\\n  - 목적: ...\\n  - 내용: ...\\n  - 일정: ..."
2. 상세 내용: 동일 내용을 3~5문장 산문으로 자연스럽게 풀어 씀
   "이번 주에는...", "~을 진행하고 있습니다", "~할 예정입니다" 형식
3. 이전 주차 내용과 자연스럽게 연속성 유지
   - 지난 주 완료된 것은 간략히 결과로 언급
   - 이번 주 진행/신규 사항 중심으로 작성
4. LG/생산기술원 HR 보고서 문체 유지 (격식체, ~합니다/~예정입니다)
5. 반드시 JSON만 반환, 다른 텍스트 없이: {"실적": "...", "상세": "..."}`;

  const user = `담당자: ${person}
년도/월/주차: ${year}년 ${month}월 ${week}
업무명: ${task.name}
태그: [${task.tag}]

이번 주 핵심 내용/키워드:
${task.keyword}

이전 주차 실적 (연속성 참고, 없으면 신규 업무로 작성):
${task.context || "(없음 — 신규 업무로 작성)"}

위 정보를 바탕으로 주간보고서를 작성해주세요.
반드시 JSON만 반환: {"실적": "...", "상세": "..."}`;

  const resp = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
      "anthropic-version": "2023-06-01",
      "anthropic-dangerous-direct-browser-access": "true"
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-20250514",
      max_tokens: 1200,
      system,
      messages: [{ role: "user", content: user }]
    })
  });

  if (!resp.ok) {
    const err = await resp.json().catch(() => ({}));
    throw new Error(err.error?.message || `API 오류 (${resp.status})`);
  }

  const data = await resp.json();
  const text = (data.content || []).map(c => c.text || "").join("").trim();
  const clean = text.replace(/^```json\s*|^```\s*|```\s*$/gm, "").trim();
  try {
    return JSON.parse(clean);
  } catch {
    return { 실적: text, 상세: "" };
  }
}

function renderOutput(year, month, week) {
  const area = document.getElementById("output-area");
  if (results.length === 0) { area.innerHTML = ""; return; }

  area.innerHTML = `
  <div class="output-section">
    <div class="output-header">
      <h2>${year}년 ${month}월 <span>${week}</span> 보고서</h2>
      <button class="btn-copy-all" onclick="copyAll()"><i class="fa fa-copy"></i> 전체 복사</button>
    </div>
    ${results.map((r, i) => {
      const tagInfo = TAG_MAP[r.task.tag] || TAG_MAP["기타"];
      return `
      <div class="output-card">
        <div class="output-card-header">
          <div class="output-card-title">
            <div class="task-number">${i + 1}</div>
            <div class="task-name-display">${escH(r.task.name).replace(/\n/g,' ')}</div>
            <span class="task-tag-badge ${tagInfo.cls}">${tagInfo.label}</span>
          </div>
        </div>
        <div class="output-cols">
          <div>
            <div class="output-col-label">
              <span><i class="fa fa-list" style="margin-right:4px;color:var(--red);"></i> 추진 업무 실적</span>
              <button class="btn-copy" onclick="copyField('out-${i}-실적',this)">복사</button>
            </div>
            <div class="output-content" id="out-${i}-실적">${escH(r.실적 || '')}</div>
          </div>
          <div>
            <div class="output-col-label">
              <span><i class="fa fa-align-left" style="margin-right:4px;color:var(--red);"></i> 상세 내용</span>
              <button class="btn-copy" onclick="copyField('out-${i}-상세',this)">복사</button>
            </div>
            <div class="output-content" id="out-${i}-상세">${escH(r.상세 || '')}</div>
          </div>
        </div>
        <button class="btn-save-ctx" id="save-ctx-${i}" onclick="saveContext(${i})">
          <i class="fa fa-arrow-down"></i> 이번 주 실적을 다음 주 맥락으로 저장
        </button>
      </div>`;
    }).join('')}
  </div>`;
}

function copyField(elId, btn) {
  const el = document.getElementById(elId);
  if (!el) return;
  navigator.clipboard.writeText(el.textContent).then(() => {
    btn.textContent = "복사됨 ✓"; btn.classList.add("copied");
    setTimeout(() => { btn.textContent = "복사"; btn.classList.remove("copied"); }, 1500);
  });
}

function copyAll() {
  const text = results.map(r =>
    `[${r.task.name.replace(/\n/g,' ')}]\n추진 업무 실적:\n${r.실적}\n\n상세 내용:\n${r.상세}`
  ).join('\n\n---\n\n');
  navigator.clipboard.writeText(text).then(() => {
    const btn = event.target.closest('button');
    btn.innerHTML = '<i class="fa fa-check"></i> 복사됨';
    setTimeout(() => { btn.innerHTML = '<i class="fa fa-copy"></i> 전체 복사'; }, 1800);
  });
}

function saveContext(idx) {
  const r = results[idx];
  if (!r) return;
  const task = tasks.find(t => t.id === r.task.id);
  if (task) {
    task.context = r.실적;
    const ctxEl = document.getElementById(`ctx-${task.id}`);
    if (ctxEl) ctxEl.value = r.실적;
  }
  const btn = document.getElementById(`save-ctx-${idx}`);
  if (btn) {
    btn.innerHTML = '<i class="fa fa-check"></i> 저장됨 — 다음 주 생성 시 자동 적용됩니다';
    btn.classList.add("saved");
    setTimeout(() => {
      btn.innerHTML = '<i class="fa fa-arrow-down"></i> 이번 주 실적을 다음 주 맥락으로 저장';
      btn.classList.remove("saved");
    }, 3000);
  }
}

function clearAll() {
  if (tasks.length > 0 && !confirm("입력한 내용을 모두 초기화할까요?")) return;
  tasks = [];
  taskId = 0;
  results = [];
  renderTasks();
  document.getElementById("output-area").innerHTML = "";
}

function showOutputAlert(msg, type) {
  document.getElementById("output-area").innerHTML =
    `<div class="alert alert-${type === 'err' ? 'err' : 'info'}">${msg}</div>`;
}

// ── UTILS ──
function escH(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}
function escJ(s) {
  return String(s).replace(/\\/g,'\\\\').replace(/'/g,"\\'").replace(/\n/g,'\\n');
}

// ── INIT ──
renderPresets();
renderTasks();
</script>
</body>
</html>
