    ['01', [
      new Paragraph({ spacing: { after: 40 }, children: [bold('console.anthropic.com 접속 후 로그인')] }),
      new Paragraph({ spacing: { after: 0 }, children: [new TextRun({ text: 'API Keys → Create Key → 키 이름 입력 (예: hr-weekly-report)', font: FONT, size: 19, color: C.gray700 })] })
