const FONT_MONO = 'D2Coding';
const PW = 9026; // A4 content width in DXA (1" margins each side)

// ─── BORDER HELPERS ───
const border = (color, size = 6) => ({ style: BorderStyle.SINGLE, size, color });
const noBorder = () => ({ style: BorderStyle.NONE, size: 0, color: 'FFFFFF' });
const cellBorders = (c) => ({ top: border(c), bottom: border(c), left: border(c), right: border(c) });

// ─── PARAGRAPH HELPERS ───
function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 360, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 8, color: C.red, space: 6 } },
    children: [new TextRun({ text, font: FONT, size: 32, bold: true, color: C.dark })]
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 280, after: 80 },
    children: [new TextRun({ text, font: FONT, size: 26, bold: true, color: C.red })]
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    spacing: { before: 200, after: 60 },
    children: [new TextRun({ text, font: FONT, size: 22, bold: true, color: C.dark })]
  });
}

function body(runs) {
  const children = Array.isArray(runs)
    ? runs.map(r => typeof r === 'string'
        ? new TextRun({ text: r, font: FONT, size: 20, color: C.dark })
        : r)
    : [new TextRun({ text: runs, font: FONT, size: 20, color: C.dark })];
  return new Paragraph({ spacing: { after: 100 }, children });
}

function bold(text, color = C.dark) {
  return new TextRun({ text, font: FONT, size: 20, bold: true, color });
}

function mono(text) {
  return new TextRun({ text, font: FONT_MONO, size: 18, color: '1E3A5F', highlight: 'cyan' });
}

function redAccent(text) {
  return new TextRun({ text, font: FONT, size: 20, bold: true, color: C.red });
}

function spacer(after = 160) {
  return new Paragraph({ spacing: { after }, children: [new TextRun('')] });
}

function bullet(text, level = 0) {
  return new Paragraph({
    numbering: { reference: 'bullets', level },
    spacing: { after: 80 },
    children: [typeof text === 'string'
      ? new TextRun({ text, font: FONT, size: 20, color: C.dark })
      : text]
  });
}

function numberedItem(text) {
  return new Paragraph({
    numbering: { reference: 'numbers', level: 0 },
    spacing: { after: 80 },
    children: [typeof text === 'string'
      ? new TextRun({ text, font: FONT, size: 20, color: C.dark })
      : text]
  });
}

// ─── CODE BLOCK ───
function codeBlock(lines) {
  const rows = lines.map(line =>
    new TableRow({
      children: [new TableCell({
        width: { size: PW, type: WidthType.DXA },
        borders: cellBorders(C.codeBorder),
        shading: { fill: '1E2D3D', type: ShadingType.CLEAR },
        margins: { top: 60, bottom: 60, left: 200, right: 200 },
        children: [new Paragraph({
          spacing: { after: 0 },
          children: [new TextRun({
            text: line,
            font: FONT_MONO,
            size: 17,
            color: line.startsWith('#') ? '7EC8A4' : line.startsWith('$') ? 'F9C74F' : 'A8D8EA'
          })]
        })]
      })]
    })
  );
  return new Table({
    width: { size: PW, type: WidthType.DXA },
    columnWidths: [PW],
    rows
  });
}

// ─── INFO BOX ───
function infoBox(label, text, fillColor = C.infoBlue, borderColor = C.infoBorder) {
  return new Table({
    width: { size: PW, type: WidthType.DXA },
    columnWidths: [PW],
    rows: [new TableRow({
      children: [new TableCell({
        width: { size: PW, type: WidthType.DXA },
        borders: {
          top: noBorder(), bottom: noBorder(), right: noBorder(),
          left: { style: BorderStyle.SINGLE, size: 20, color: borderColor }
        },
        shading: { fill: fillColor, type: ShadingType.CLEAR },
        margins: { top: 80, bottom: 80, left: 200, right: 200 },
        children: [
          new Paragraph({ spacing: { after: 40 }, children: [new TextRun({ text: label, font: FONT, size: 18, bold: true, color: borderColor })] }),
          new Paragraph({ spacing: { after: 0 }, children: [new TextRun({ text, font: FONT, size: 19, color: C.gray700 })] })
        ]
      })]
    })]
  });
}

// ─── STEP TABLE (2-col) ───
function stepTable(rows) {
  return new Table({
    width: { size: PW, type: WidthType.DXA },
    columnWidths: [1200, PW - 1200],
    rows: rows.map(([step, content]) => new TableRow({
      children: [
        new TableCell({
          width: { size: 1200, type: WidthType.DXA },
          borders: cellBorders(C.gray300),
          shading: { fill: C.red, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          verticalAlign: 'center',
          children: [new Paragraph({
            alignment: AlignmentType.CENTER,
            children: [new TextRun({ text: step, font: FONT, size: 20, bold: true, color: C.white })]
          })]
        }),
        new TableCell({
          width: { size: PW - 1200, type: WidthType.DXA },
          borders: cellBorders(C.gray300),
          shading: { fill: C.white, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 200, right: 120 },
          children: Array.isArray(content) ? content : [new Paragraph({ children: [new TextRun({ text: content, font: FONT, size: 20, color: C.dark })] })]
        })
      ]
    }))
  });
}

// ─── MATRIX TABLE (header + rows) ───
function matrixTable(headers, rows) {
  const colW = Math.floor(PW / headers.length);
  const colWidths = headers.map((_, i) => i === headers.length - 1 ? PW - colW * (headers.length - 1) : colW);

  const headerRow = new TableRow({
    tableHeader: true,
    children: headers.map((h, i) => new TableCell({
      width: { size: colWidths[i], type: WidthType.DXA },
      borders: cellBorders(C.red),
      shading: { fill: C.dark, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      children: [new Paragraph({ alignment: AlignmentType.CENTER, children: [new TextRun({ text: h, font: FONT, size: 18, bold: true, color: C.white })] })]
    }))
  });

  const dataRows = rows.map((row, ri) => new TableRow({
    children: row.map((cell, ci) => new TableCell({
      width: { size: colWidths[ci], type: WidthType.DXA },
      borders: cellBorders(C.gray300),
      shading: { fill: ri % 2 === 0 ? C.white : C.gray100, type: ShadingType.CLEAR },
      margins: { top: 60, bottom: 60, left: 120, right: 120 },
      children: [new Paragraph({ children: [
        typeof cell === 'string'
          ? new TextRun({ text: cell, font: FONT, size: 19, color: C.dark })
          : cell
      ]})]
    }))
  }));

  return new Table({ width: { size: PW, type: WidthType.DXA }, columnWidths: colWidths, rows: [headerRow, ...dataRows] });
}

